#include <stdio.h>
#include <stdbool.h>

bool ok(int *A, int N, int Y) {
    int first = A[0] | Y;
    for (int i = 1; i < N; ++i) {
        if ((A[i] | Y) != first) return true; // at least two distinct
    }
    return false;
}

int main() {
    int T; scanf("%d", &T);
    while (T--) {
        int N, X; scanf("%d %d", &N, &X);
        int A[100000];
        for (int i = 0; i < N; ++i) scanf("%d", &A[i]);
        int ans = 0;
        for (int b = 29; b >= 0; --b) {
            int cand = ans | (1 << b);
            if (cand <= X && ok(A, N, cand)) ans = cand;
        }
        printf("%d\n", ans);
    }
    return 0;
}

