import sys

def ok(arr, y):
    first = arr[0] | y
    for v in arr[1:]:
        if (v | y) != first:
            return True
    return False

def solve():
    data = sys.stdin.buffer.read().split()
    if not data:
        return
    it = iter(data)
    t = int(next(it))
    out = []
    for _ in range(t):
        n = int(next(it)); x = int(next(it))
        a = [int(next(it)) for _ in range(n)]
        ans = 0
        for b in range(29, -1, -1):
            cand = ans | (1 << b)
            if cand <= x and ok(a, cand):
                ans = cand
        out.append(str(ans))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

